Use `{{has-block}}` to check if block content was provided before yielding.

```gjs
import Component from '@glimmer/component';

export default class OptionalSlot extends Component {
  <template>
    <div class="rounded-lg border p-4">
      <h3 class="font-bold text-gray-900">{{@title}}</h3>
      {{#if (has-block)}}
        <div class="mt-3 border-t pt-3">
          {{yield}}
        </div>
      {{else}}
        <p class="mt-2 text-sm text-gray-500">{{@description}}</p>
      {{/if}}
    </div>
  </template>
}
```

`{{has-block}}` returns `true` if the parent passed block content. Use it to provide a sensible fallback when the block is omitted.

Use multiple `{{on}}` modifiers on the same element.

```gjs
import Component from '@glimmer/component';
import { action } from '@ember/object';
import { tracked } from '@glimmer/tracking';

export default class HoverCard extends Component {
  @tracked isHovered = false;

  @action onMouseEnter() { this.isHovered = true; }
  @action onMouseLeave() { this.isHovered = false; }

  <template>
    <div
      class="relative p-3 border rounded cursor-pointer transition-shadow
        {{if this.isHovered 'shadow-lg' 'shadow-sm'}}"
      {{on "mouseenter" this.onMouseEnter}}
      {{on "mouseleave" this.onMouseLeave}}
      {{on "click" @onClick}}
    >
      {{@title}}
      {{#if this.isHovered}}
        <div class="absolute top-full left-0 mt-1 bg-white border rounded shadow-xl p-3 z-10 w-48">
          <p class="text-sm text-gray-600">{{@hoverContent}}</p>
        </div>
      {{/if}}
    </div>
  </template>
}
```

You can stack as many `{{on}}` modifiers as needed — each registers its own listener independently.

Pass the action using `@onActionName={{this.handler}}` and call it with `@onActionName()` or in an event handler.

```gjs
import Component from '@glimmer/component';
import { action } from '@ember/object';
import ScoreInput from './score-input';

export default class ScoreForm extends Component {
  @action
  handleScoreSubmit(score) {
    console.log('Score submitted:', score);
    this.args.onComplete?.(score);
  }

  <template>
    <div class="p-4">
      <h2 class="font-bold mb-3">Enter Score</h2>
      <ScoreInput
        @matchId={{@matchId}}
        @onSubmit={{this.handleScoreSubmit}}
        @onCancel={{@onDismiss}}
