const tooltipModifier = modifier((element, [text]) => {
  // INSTALL: runs when element enters DOM
  const tooltip = document.createElement('div');
  tooltip.className = 'tooltip-popup';
  tooltip.textContent = text;
  element.appendChild(tooltip);

  const show = () => tooltip.classList.add('visible');
  const hide = () => tooltip.classList.remove('visible');
  element.addEventListener('mouseenter', show);
  element.addEventListener('mouseleave', hide);

  // TEARDOWN: cleanup function — runs when element leaves DOM
  return () => {
    element.removeEventListener('mouseenter', show);
    element.removeEventListener('mouseleave', hide);
    tooltip.remove();
  };
});

export default class PlayerBadge extends Component {
  <template>
    <span
      class="cursor-help underline decoration-dotted"
      {{tooltipModifier @player.bio}}
    >
      {{@player.name}}
    </span>
  </template>
}
```

This lifecycle model makes modifiers **the right place** for any logic that must respond to DOM element existence.

GJS template-tag co-locates the template and JavaScript in one file, eliminating the split-brain problem of classic Ember.

**Key advantages:**

1. **Single file** — No more switching between `my-component.js` and `my-component.hbs`. Everything is in `my-component.gjs`.

2. **Standard JavaScript module scope** — Imported components, helpers, and modifiers are directly available in the template without registration in a global registry.

3. **Better tooling** — TypeScript, ESLint, and Prettier can analyze the whole file as one unit.

4. **No magic string resolution** — In .hbs, `{{my-component}}` worked via string lookup in Ember's registry. In GJS, `<MyComponent />` works via an explicit import — refactoring tools understand it.

5. **Explicit dependencies** — You can see exactly what a component uses just by looking at the imports.

```gjs
// ✅ GJS — everything explicit, one file
import Component from '@glimmer/component';
import PlayerCard from './player-card'; // explicit import

export default class TeamList extends Component {
  <template>
    {{#each @players as |p|}}
      <PlayerCard @player={{p}} />  {{! no registry lookup }}
    {{/each}}
  </template>
}
```

GJS is the future of Ember — Embroider + Vite can tree-shake unused components, which was impossible with the global registry model.

Glimmer enforces one-way data flow: data flows down from parent to child via args, and events flow up via callbacks. Children never directly modify parent state.

**The pattern:**

```gjs
// ✅ Parent owns the state
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';
import WicketCounter from './wicket-counter';

export default class Scorecard extends Component {
  @tracked wickets = 0;  // state lives here

  @action
  addWicket() {
    this.wickets += 1;  // only parent modifies state
  }

  <template>
    <WicketCounter
      @count={{this.wickets}}      {{!-- data flows DOWN --}}
      @onWicket={{this.addWicket}} {{!-- event flows UP via callback --}}
    />
  </template>
}
```

```gjs
// ✅ Child receives data and emits events
export default class WicketCounter extends Component {
  <template>
    <div class="flex items-center gap-3">
      <span class="text-2xl font-bold">{{@count}}</span>
      <button type="button" {{on "click" @onWicket}}>+Wicket</button>
    </div>
  </template>
}
```

**Why it matters:** Predictable state management. When something breaks, you know state only changed in one place. This makes debugging and testing dramatically simpler.

Args are immutable because they belong to the parent — the child didn't create them and shouldn't change them. Mutating args would break one-way data flow and create unpredictable, hard-to-debug state.

**Why the framework prevents it:**

```gjs
// ❌ WRONG — mutating args, will throw in development mode
export default class BadComponent extends Component {
  @action
  updateScore() {
    this.args.score += 10;  // TypeError: Cannot assign to read only property
  }
}
```

**What to do instead:**

Option 1 — Lift state up to parent:
```gjs
// Parent owns the state
export default class Parent extends Component {
  @tracked score = 0;
  @action updateScore() { this.score += 10; }
  <template>
    <Child @score={{this.score}} @onUpdate={{this.updateScore}} />
  </template>
}
```

Option 2 — Copy to local tracked state (for local UI state):
```gjs
export default class Child extends Component {
  @tracked localScore = this.args.score;  // copy on init
  @action updateScore() { this.localScore += 10; }  // update local copy
}
```

Choose Option 1 when the parent cares about the change. Choose Option 2 for purely local UI state (e.g., a temp editing value before a form is submitted).

These three primitives serve distinct purposes in Glimmer's template model:

| | **Component** | **Helper** | **Modifier** |
|---|---|---|---|
| **Returns** | HTML/DOM structure | A value | Side effects on a DOM element |
| **Has template** | Yes | No | No |
| **Accesses DOM** | Indirectly (via template) | No | Yes (element passed directly) |
| **Usage** | `<MyComp />` | `(myHelper arg)` or `{{myHelper arg}}` | `{{myModifier}}` |

```gjs
