import { modifier } from 'ember-modifier';

// HELPER — computes a value
const toFixed = (n, decimals = 2) => Number(n).toFixed(decimals);

// MODIFIER — touches the DOM
const autofocus = modifier((element) => {
  element.focus();
});

// COMPONENT — renders HTML
export default class StrikeRateDisplay extends Component {
  <template>
    <div {{autofocus}}>
      <span class="text-xl font-bold">
        SR: {{toFixed @strikeRate 1}}
      </span>
    </div>
  </template>
}
```

**Rule of thumb:** Need HTML? → Component. Need a computed value? → Helper. Need to touch a DOM node? → Modifier.

