// Only visible inside this file — zero coupling to rest of app
const formatOvers = (balls) => `${Math.floor(balls/6)}.${balls%6}`;
const runRate = (runs, balls) => balls ? ((runs/(balls/6)).toFixed(2)) : '0.00';

export default class LiveScore extends Component {
