import { formatCurrency } from '../helpers/format-currency';

export default class TicketCard extends Component {
  <template>
    <p>{{formatDate @match.date "dd MMM yyyy"}}</p>
    <p>{{formatCurrency @ticket.price "BDT"}}</p>
  </template>
}
```

