export default class BaseButton extends Component {
  <template>
    <button
      type="button"
      class="px-4 py-2 rounded font-medium"
      ...attributes  {{!-- consumer adds: disabled, aria-*, data-*, {{on}} --}}
    >
      {{yield}}
    </button>
  </template>
}

// Consumer:
// <BaseButton disabled={{@isBusy}} aria-label="Submit score" {{on "click" @submit}}>
//   Submit
// </BaseButton>
```

