export default class ScoreCard extends Component {
  <template>
    <article
      class="bg-white rounded-lg shadow p-4"
      role="region"
      aria-label={{concat @homeTeam " vs " @awayTeam}}
    >
      {{!-- No ...attributes — this is an opinionated layout component --}}
      <h2>{{@homeTeam}} vs {{@awayTeam}}</h2>
    </article>
  </template>
}
```

Rule: Primitive UI elements (`button`, `input`, wrapper `div`) → `...attributes`. Business/domain components with specific semantics → explicit.

