**Use a modifier** when you need access to a specific DOM element. **Use class lifecycle hooks** for logic that doesn't require the DOM.

```gjs
import Component from '@glimmer/component';
import { service } from '@ember/service';
import { modifier } from 'ember-modifier';

const focusOnMount = modifier((element) => {
  element.focus();
  // ✅ MODIFIER: needs specific DOM element
});

export default class SearchModal extends Component {
  @service analytics;

  constructor(owner, args) {
    super(owner, args);
    // ✅ CONSTRUCTOR: no DOM needed, just JS setup
    this.analytics.track('modal_opened', { context: args.context });
  }

  willDestroy() {
    super.willDestroy();
    // ✅ WILLDESTROYCD: cleanup JS state, cancel subscriptions
    this.analytics.track('modal_closed');
  }

  <template>
    <div class="modal p-6">
      <input
        type="search"
        class="border rounded w-full px-3 py-2"
        {{focusOnMount}}   {{!-- DOM interaction → modifier --}}
        {{on "input" @onSearch}}
      />
    </div>
  </template>
}
```

