**Use `{{fn}}`** for passing args to an existing action in an `{{each}}` loop or when binding a parent's callback with data. **Use `@action`** when the handler contains meaningful logic.

```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class BowlingCard extends Component {
  @tracked selectedBowler = null;

  @action
  selectBowler(bowler) {
    this.selectedBowler = bowler;
    this.args.onBowlerChange?.(bowler);
  }

  <template>
    <ul class="space-y-1">
      {{#each @bowlers as |bowler|}}
        <li>
          <button
            type="button"
            class="w-full text-left p-2 rounded hover:bg-gray-50"
            {{on "click" (fn this.selectBowler bowler)}}
          >
            {{bowler.name}} — {{bowler.wickets}} wkts
