```gjs
// ✅ CORRECT — store handler reference, return cleanup function
import { modifier } from 'ember-modifier';
import Component from '@glimmer/component';
import { action } from '@ember/object';

const keyboardNav = modifier((element, [onUp, onDown]) => {
  const handleKeyDown = (e) => {  // ✅ named reference
    if (e.key === 'ArrowUp') { e.preventDefault(); onUp(); }
    if (e.key === 'ArrowDown') { e.preventDefault(); onDown(); }
  };

  element.addEventListener('keydown', handleKeyDown);

  return () => {  // ✅ cleanup function
    element.removeEventListener('keydown', handleKeyDown);
  };
});

export default class PlayerList extends Component {
  <template>
    <ul
      tabindex="0"
      class="focus:outline-none focus:ring-2 focus:ring-green-400 rounded"
      {{keyboardNav @onSelectPrev @onSelectNext}}
    >
      {{#each @players as |player|}}
        <li class="p-2 cursor-pointer hover:bg-gray-50">{{player.name}}</li>
      {{/each}}
    </ul>
  </template>
}
```

