import LiveScore from './live-score';

export default class Dashboard extends Component {
  <template>
    {{live-score matchId=@matchId}}  {{!-- Error: this is helper syntax, not component --}}
    {{live-score @matchId=@matchId}} {{!-- Error: curly invocation not supported in GJS --}}
  </template>
}
```

```gjs
// ✅ CORRECT — angle bracket syntax always in GJS
import Component from '@glimmer/component';
import LiveScore from './live-score';

export default class Dashboard extends Component {
  <template>
    <LiveScore @matchId={{@matchId}} />

    {{!-- For self-closing: <MyComponent /> --}}
    {{!-- For block form: <MyComponent>...</MyComponent> --}}
    {{!-- Named component with PascalCase always --}}
  </template>
}
```

