A live score ticker with polling, loading states, and proper cleanup.

```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';
import { didInsert, willDestroy } from '@ember/render-modifiers';

export default class LiveScoreTicker extends Component {
  @tracked score = null;
  @tracked isLoading = true;
  @tracked error = null;
  @tracked lastUpdated = null;

  intervalId = null;

  @action
  async startPolling(element) {
    await this.fetchScore();
    this.intervalId = setInterval(() => this.fetchScore(), 30_000);
  }

  @action
  stopPolling() {
    clearInterval(this.intervalId);
    this.intervalId = null;
  }

  async fetchScore() {
    this.error = null;
    try {
      const res = await fetch(`/api/matches/${this.args.matchId}/live-score`);
      if (!res.ok) throw new Error('Failed to fetch');
      this.score = await res.json();
      this.lastUpdated = new Date();
    } catch (err) {
      this.error = 'Could not load score';
    } finally {
      this.isLoading = false;
    }
  }

  get timeAgo() {
    if (!this.lastUpdated) return '';
    const secs = Math.floor((Date.now() - this.lastUpdated) / 1000);
    if (secs < 5) return 'just now';
    return `${secs}s ago`;
  }

  <template>
    <div
      class="bg-green-800 text-white p-4 rounded-lg"
      {{didInsert this.startPolling}}
      {{willDestroy this.stopPolling}}
    >
      <div class="flex items-center justify-between mb-2">
        <span class="text-xs uppercase tracking-wide text-green-300">Live Score</span>
        <span class="text-xs text-green-400">Updated {{this.timeAgo}}</span>
      </div>

      {{#if this.isLoading}}
        <div class="animate-pulse space-y-2">
          <div class="h-6 bg-green-700 rounded w-3/4"></div>
          <div class="h-4 bg-green-700 rounded w-1/2"></div>
        </div>
      {{else if this.error}}
        <p class="text-red-300 text-sm">{{this.error}}</p>
      {{else}}
        <div class="space-y-1">
          <p class="text-2xl font-bold">
            {{this.score.runs}}/{{this.score.wickets}}
            <span class="text-base font-normal text-green-300">({{this.score.overs}} ov)</span>
          </p>
          <p class="text-sm text-green-200">{{this.score.commentary}}</p>
        </div>
      {{/if}}
    </div>
  </template>
}
```

