A flexible modal with named blocks, keyboard accessibility, and backdrop click to close.

```gjs
import Component from '@glimmer/component';
import { action } from '@ember/object';
import { modifier } from 'ember-modifier';

const trapFocus = modifier((element) => {
  const focusable = element.querySelectorAll(
    'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
  );
  const first = focusable[0];
  const last = focusable[focusable.length - 1];

  const handleTab = (e) => {
    if (e.key !== 'Tab') return;
    if (e.shiftKey && document.activeElement === first) {
      e.preventDefault(); last?.focus();
    } else if (!e.shiftKey && document.activeElement === last) {
      e.preventDefault(); first?.focus();
    }
  };

  element.addEventListener('keydown', handleTab);
  first?.focus();

  return () => element.removeEventListener('keydown', handleTab);
});

export default class Modal extends Component {
  @action
  handleBackdropClick(e) {
    if (e.target === e.currentTarget) {
      this.args.onClose?.();
    }
  }

  @action
  handleKeyDown(e) {
    if (e.key === 'Escape') this.args.onClose?.();
  }

  <template>
    {{#if @isOpen}}
      <div
        class="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm"
        role="dialog"
        aria-modal="true"
        {{on "click" this.handleBackdropClick}}
        {{on "keydown" this.handleKeyDown}}
      >
        <div
          class="bg-white rounded-2xl shadow-2xl w-full max-w-lg mx-4 overflow-hidden"
          {{trapFocus}}
        >
          {{!-- Header --}}
          <header class="flex items-center justify-between px-6 py-4 border-b bg-green-700 text-white">
            <div class="font-bold text-lg">
              {{yield to="header"}}
            </div>
            <button
              type="button"
              class="text-white/80 hover:text-white transition-colors p-1 rounded"
              aria-label="Close modal"
              {{on "click" @onClose}}
            >
              ✕
            </button>
          </header>

          {{!-- Body --}}
          <div class="px-6 py-5 max-h-96 overflow-y-auto">
            {{yield to="body"}}
          </div>

          {{!-- Footer --}}
          {{#if (has-block "footer")}}
            <footer class="px-6 py-4 border-t bg-gray-50 flex justify-end gap-3">
              {{yield to="footer"}}
            </footer>
          {{/if}}
        </div>
      </div>
    {{/if}}
  </template>
}
