import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';
import { eq } from 'ember-truth-helpers';

export default class TabNav extends Component {
  @tracked activeTab = this.args.tabs?.[0]?.id;

  @action
  selectTab(tabId) {
    this.activeTab = tabId;
    this.args.onChange?.(tabId);
  }

  @action
  handleKeyDown(e) {
    const tabs = this.args.tabs ?? [];
    const currentIndex = tabs.findIndex(t => t.id === this.activeTab);
    if (e.key === 'ArrowRight') {
      const next = tabs[(currentIndex + 1) % tabs.length];
      this.selectTab(next.id);
    } else if (e.key === 'ArrowLeft') {
      const prev = tabs[(currentIndex - 1 + tabs.length) % tabs.length];
      this.selectTab(prev.id);
    }
  }

  <template>
    <div class="w-full">
      {{!-- Tab List --}}
      <div
        class="flex border-b border-gray-200 overflow-x-auto"
        role="tablist"
        aria-label={{@ariaLabel}}
        {{on "keydown" this.handleKeyDown}}
      >
        {{#each @tabs as |tab|}}
          <button
            type="button"
            role="tab"
            aria-selected={{eq this.activeTab tab.id}}
            class="relative px-5 py-3 text-sm font-medium whitespace-nowrap transition-colors
              {{if (eq this.activeTab tab.id)
                'text-green-700 border-b-2 border-green-600 -mb-px'
                'text-gray-500 hover:text-gray-700 hover:bg-gray-50'
