          {{!-- Footer --}}
          {{#if (has-block "footer")}}
            <footer class="px-6 py-4 border-t bg-gray-50 flex justify-end gap-3">
              {{yield to="footer"}}
            </footer>
          {{/if}}
        </div>
      </div>
    {{/if}}
  </template>
}
